struct Node
{
    int data;
    Node *next;
};

class SinglyLinkedList
{
private:
    Node *head; // only the head needs to be remembered — everything else is reachable through it

public:
    SinglyLinkedList()
    {
        head = nullptr;
    }
};

void insertAtEnd(int value)
{
    Node *newNode = new Node{value, nullptr};

    if (head == nullptr) // empty list — the new node BECOMES head
    {
        head = newNode;
        return;
    }

    Node *current = head;
    while (current->next != nullptr) // walk to the LAST node
    {
        current = current->next;
    }
    current->next = newNode; // link it in
}

#include <iostream>

using namespace std;

struct Node
{
    int data;
    Node *next;
};

class SinglyLinkedList
{
private:
    Node *head;

public:
    SinglyLinkedList()
    {
        head = nullptr;
    }

    void insertAtEnd(int value)
    {
        Node *newNode = new Node{value, nullptr};

        if (head == nullptr)
        {
            head = newNode;
            return;
        }

        Node *current = head;
        while (current->next != nullptr)
        {
            current = current->next;
        }
        current->next = newNode;
    }

    void print()
    {
        Node *current = head;
        while (current != nullptr)
        {
            cout << current->data << " ";
            current = current->next;
        }
        cout << endl;
    }
};

int main()
{
    SinglyLinkedList list;
    list.insertAtEnd(10);
    list.insertAtEnd(20);
    list.insertAtEnd(30);

    list.print();

    return 0;
}

void deleteValue(int value)
{
    if (head == nullptr) return;

    if (head->data == value) // deleting the HEAD itself
    {
        Node *temp = head;
        head = head->next;
        delete temp;
        return;
    }

    Node *current = head;
    while (current->next != nullptr && current->next->data != value)
    {
        current = current->next;
    }

    if (current->next != nullptr) // found it
    {
        Node *temp = current->next;
        current->next = current->next->next; // SKIP over the node being deleted
        delete temp; // free its memory (recall delete)
    }
}

